import Link from 'next/link';
import { SearchInput } from '@/components/search/SearchInput';
import { FilterBar } from '@/components/search/FilterBar';
import { MarketCard } from '@/components/markets/MarketCard';
import { Button } from '@/components/ui/button';

const baseUrl =
  process.env.NEXT_PUBLIC_URL ??
  (process.env.VERCEL_URL ? `https://${process.env.VERCEL_URL}` : 'http://localhost:3000');

const LIMIT = 20;

interface SearchPageProps {
  searchParams: Promise<{
    q?: string;
    platform?: 'POLYMARKET' | 'KALSHI' | 'ALL';
    category?: string;
    page?: string;
  }>;
}

export default async function SearchPage({ searchParams }: SearchPageProps) {
  const params = await searchParams;
  const q = (params.q ?? '').trim();
  const platform = params.platform && params.platform !== 'ALL' ? params.platform : undefined;
  const category = params.category ?? undefined;
  const page = Math.max(1, parseInt(params.page ?? '1', 10));
  const offset = (page - 1) * LIMIT;

  const searchParamsUrl = new URLSearchParams();
  if (q) searchParamsUrl.set('q', q);
  if (platform) searchParamsUrl.set('platform', platform);
  if (category) searchParamsUrl.set('category', category);
  searchParamsUrl.set('limit', String(LIMIT));
  searchParamsUrl.set('offset', String(offset));

  let data: {
    markets: Array<{
      id: string;
      platform: 'POLYMARKET' | 'KALSHI';
      question: string;
      category: string | null;
      volume24h: number;
      liquidity: number;
      active: boolean;
      endDate: string | null;
      url: string | null;
      eventTitle: string | null;
      tags: string[];
    }>;
    total: number;
    offset: number;
    limit: number;
  } = { markets: [], total: 0, offset: 0, limit: LIMIT };

  if (q.length >= 2) {
    try {
      const res = await fetch(`${baseUrl}/api/markets/search?${searchParamsUrl.toString()}`, {
        next: { revalidate: 60 }
      });
      data = await res.json();
    } catch {
      data = { markets: [], total: 0, offset: 0, limit: LIMIT };
    }
  }

  const { markets, total } = data;
  const totalPages = Math.ceil(total / LIMIT);
  const hasNext = page < totalPages;
  const hasPrev = page > 1;

  const nextParams = new URLSearchParams(params as Record<string, string>);
  nextParams.set('page', String(page + 1));
  const prevParams = new URLSearchParams(params as Record<string, string>);
  prevParams.set('page', String(page - 1));

  return (
    <div className="container px-4 py-8">
      <div className="mx-auto max-w-4xl space-y-6">
        <SearchInput defaultValue={q} />

        {q.length < 2 ? (
          <div className="rounded-lg border border-white/10 bg-white/5 px-6 py-16 text-center text-muted-foreground">
            Enter a search term to find markets
          </div>
        ) : (
          <>
            <FilterBar
              currentPlatform={platform ?? 'ALL'}
              currentCategory={category ?? ''}
              totalResults={total}
            />

            <p className="text-sm text-muted-foreground">
              Showing {markets.length > 0 ? offset + 1 : 0}–{offset + markets.length} of{' '}
              {total.toLocaleString()} results for &quot;{q}&quot;
            </p>

            {markets.length === 0 ? (
              <div className="rounded-lg border border-white/10 bg-white/5 px-6 py-16 text-center">
                <p className="text-muted-foreground">
                  No markets found for &quot;{q}&quot;. Try different keywords.
                </p>
              </div>
            ) : (
              <>
                <div className="grid gap-4 sm:grid-cols-1 md:grid-cols-2 lg:grid-cols-2">
                  {markets.map((m) => (
                    <MarketCard
                      key={m.id}
                      id={m.id}
                      platform={m.platform}
                      question={m.question}
                      category={m.category}
                      volume24h={m.volume24h}
                      liquidity={m.liquidity}
                      active={m.active}
                      endDate={m.endDate}
                      url={m.url}
                      eventTitle={m.eventTitle}
                      tags={m.tags ?? []}
                    />
                  ))}
                </div>

                {totalPages > 1 && (
                  <div className="flex items-center justify-center gap-4 pt-8">
                    <Button variant="outline" size="sm" asChild disabled={!hasPrev}>
                      <Link href={hasPrev ? `/search?${prevParams.toString()}` : '#'}>
                        Previous
                      </Link>
                    </Button>
                    <span className="text-sm text-muted-foreground">
                      Page {page} of {totalPages}
                    </span>
                    <Button variant="outline" size="sm" asChild disabled={!hasNext}>
                      <Link href={hasNext ? `/search?${nextParams.toString()}` : '#'}>
                        Next
                      </Link>
                    </Button>
                  </div>
                )}
              </>
            )}
          </>
        )}
      </div>
    </div>
  );
}
